+/// Count regular files recursively under `dir`.
+fn count_files_in_dir(dir: &Path) -> Result<u64, std::io::Error> {
+    let mut count = 0u64;
+    for entry in std::fs::read_dir(dir)? {
+        let entry = entry?;
+        let ft = entry.file_type()?;
+        if ft.is_file() {
+            count += 1;
+        } else if ft.is_dir() {
+            count += count_files_in_dir(&entry.path()).unwrap_or(0);
+        }
+    }
+    Ok(count)
+}
